  .pipeThrough(new TextDecoderStream())
  .pipeThrough(new TransformStream({
    transform(chunk, controller) {
      const lines = chunk.split('\n');
      for (const line of lines) {
        if (line.startsWith('data: '))
          controller.enqueue(
            JSON.parse(line.slice(6))
          );
      }
